const fetch = require('node-fetch');
  async function extractMetaData(url){
    const response = await fetch(`https://opengraph.io/api/${url}`); // This call will throw an error if the URL cannot be accessed. Use this as a template to resolve that problem!
    const htmlDoc = await response.text();
    console.log("htmlDoc: ", htmlDoc);

    var description_str;
    var title_str;

    var str = "<p>Description: </p>"; // This line should be able to handle any possible format of opening and closing tags
    for (let i = 0 ; i<htmlDoc.length ; i++){
        if (htmlDoc[i] == 'D' && htmlDoc[i+1] == 'e' && htmlDoc[i+2] == 's' 
            && htmlDoc[i+3] == 'c'){
            for(let j = 0; j < 7 ; j++){
                if (htmlDoc [ i + j ] != str.charAt(j)) {
                    break;
                } else {
                    continue;
                }

                var count = 1;
                while ( htmlDoc[i+count] == str.charAt(j) ){
                    console.log("str.charAt(j): ", str.charAt(j));
                    j++;
                    if (htmlDoc[i + 7 - j] != '>' && j <= 5){
                        continue; // The opening tag is not found yet.
                    } else {
                        break; 
                    }
                }
            }

            for(let k = i+count ; htmlDoc [k]!='<'; ++k){
                console.log("htmlDoc[i+count]: ", htmlDoc[i+count]);
                description_str += htmlDoc[k];
            }
            break;
        }
    }

    var str2 = '<title>'; // This line should be able to handle any possible format of opening and closing tags
    
    for (let i = 0 ; i<htmlDoc.length ; i++){
        if (htmlDoc[i] == 'T' && htmlDoc[i+1] == 'i'){
            for(let j = 4; j < 8 ; j++){
                console.log("htmlDoc[j]: ", htmlDoc[j]);

                // For simplicity, we assume the title is within one tag only.
                
                if (htmlDoc [ i + j ] != str2.charAt(j)){
                    break; 
                } else {

                    for(let k = 0 ;k < 7 ; ++k){
                        if( htmlDoc[i+8-k] == '/' ){
                            console.log("htmlDoc[j]: ", htmlDoc [ i + j ]);
                            console.log("str2.charAt(j): ", str2.charAt(j));
                            break; 
                        } else{
                            continue ; 
                            //continue;
                        }
                    }
                }

                var count = 1;
                while ( htmlDoc[i+count] == str2.charAt(j) ){
                    
                    j++;
                    if (htmlDoc [ i + 8 - j ] != str2.charAt(7-j)){

                        break;

                    } else{
                        continue ;
                    }

                    for(let k = 0; k < count ; ++k){
                        console.log("htmlDoc[i+count]: ", htmlDoc[i+count]);
                        title_str += htmlDoc [ i + j ]; 
                    }
                }
            }
        }
    }

    return description_str, title_str;
}


